UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('b0522d65-5e43-4b5f-9c0a-bfe92ace94b4'::uuid, 'L''insuffisance veineuse dilate les veines, les bas de contention exercent une compression pour soutenir les parois vasculaires et améliorer le retour sanguin.'),('63352ab5-7917-4f45-9f38-f0ddb10cc5d0'::uuid, 'L''insuffisance veineuse entraîne une mauvaise circulation, ce veinotonique renforce les parois des vaisseaux pour réduire la stase et le gonflement.'),('b5811086-e4c2-4fa0-acf1-dd2d704936c3'::uuid, 'Les varices peuvent causer des jambes lourdes, cette crème soulage la sensation de pesanteur en activant la circulation locale.'),('3d7b2dbe-5e5f-40e2-897f-c87b9873a538'::uuid, 'Les vergetures résultent d''une rupture des fibres de collagène, cette huile nourrit la peau et améliore son élasticité.'),('d37bc2a6-1014-4176-9175-f354683f427b'::uuid, 'La formation des vergetures est due à un manque de collagène, le collagène marin renforce la peau et prévient leur apparition.'),('98e90726-b72d-4dc4-abf3-89d61444a60e'::uuid, 'Les vergetures sont des lésions cutanées, cette crème stimule la production de collagène et favorise la réparation tissulaire.'),('295d53a9-21dd-4c7a-b035-a27509c3fcc8'::uuid, 'Les verrues sont des excroissances cutanées, cette solution kératolytique dissout les couches de cellules infectées et élimine la verrue.'),('ce33286a-7aee-4c68-9c68-10cb20d05c30'::uuid, 'Les verrues sont formées par une prolifération cellulaire, l''acide salicylique détruit progressivement les cellules infectées et aide à la disparition.'),('99486381-30e2-4130-9307-a7ae2633ca49'::uuid, 'Les verrues sont causées par un virus, la cryothérapie gèle et détruit les cellules infectées pour les éliminer rapidement.'),('702cb653-0af3-427d-932c-fdc9895d238d'::uuid, 'Les verrues sont des lésions cutanées épaisses, l''acide salicylique agit pour détruire la verrue couche par couche et la faire disparaitre.'),('6c09bf47-f54d-4df5-8aa9-929237152b01'::uuid, 'Les verrues sont causées par un virus, la cryothérapie gèle et détruit les tissus de la verrue pour l''éradiquer efficacement.'),('7b4da60c-dc64-4884-8491-8141960bb7e1'::uuid, 'Les verrues peuvent se propager par contact, les pansements protègent la verrue des frottements et limitent la dissémination virale.'),('686beab7-2ec0-4ca1-8c6a-e7fb8155c715'::uuid, 'Les vertiges peuvent s''accompagner de nausées, le gingembre aide à calmer l''estomac et à réduire la sensation d''écœurement.'),('960b25f2-9ee3-4fd6-a990-8a0ab0c4878f'::uuid, 'Les vertiges peuvent être liés à une mauvaise irrigation cérébrale, le ginkgo biloba améliore la circulation sanguine et réduit les étourdissements.'),('2d25f5d1-c27e-47d1-9404-17a49c7f41c4'::uuid, 'Les vertiges peuvent être causés par un déséquilibre neurologique, le magnésium B6 soutient le fonctionnement du système nerveux et aide à stabiliser.'),('2055aded-0017-4667-8054-5a05e613250c'::uuid, 'Le vieillissement cutané est dû au stress oxydatif, la vitamine C antioxydante protège les cellules de la peau et limite les dommages.'),('485ef02a-4f36-439a-8cfc-b0fb2f5b68d9'::uuid, 'La perte de collagène entraîne un relâchement cutané, le collagène marin oral restaure l''élasticité de la peau et réduit les rides.'),('e5ad3552-d3e4-4255-be42-d895f7bf5c6f'::uuid, 'Le vieillissement cutané se manifeste par une déshydratation, l''acide hyaluronique maintient l''hydratation de la peau et améliore sa tonicité.'),('e002e7ad-29d5-4ab1-8f71-4cb5ea1cc9e2'::uuid, 'Les vomissements entraînent une perte significative de liquides et d''électrolytes, la SRO compense cette déshydratation pour prévenir les complications.'),('d74a4ca5-ecf3-4035-b8ce-8689e96e2e6e'::uuid, 'Les vomissements vident le corps de son eau et de ses minéraux, la solution de réhydratation compense ces pertes et rétablit l''équilibre hydrique.'),('56916e78-7d4d-4d63-951e-e10d216416b3'::uuid, 'Les vomissements peuvent être précédés de nausées, le gingembre agit sur le centre vomitif et aide à apaiser l''estomac.'),('f30db8d6-345a-4734-b773-786da28655cb'::uuid, 'Le zona provoque des vésicules douloureuses, l''antiseptique nettoie la peau et prévient la surinfection bactérienne des lésions.'),('6e5cb81b-a2db-452d-ad54-7e0499592eb3'::uuid, 'Les lésions du zona sont très fragiles, les pansements non adhérents protègent la peau et permettent une cicatrisation sans traumatisme.'),('cbd7c8e2-0851-449b-9686-01b870bc76da'::uuid, 'Le zona laisse des marques sur la peau, la crème cicatrisante favorise la régénération cellulaire et atténue les séquelles cutanées.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;